package main

import (
	"fmt"
	"time"
)

func main() {
	today := time.Now().Weekday()
	switch time.Saturday {
	case today + 0:
		fmt.Println("Сегодня суббота! 🎉")
	case today + 1:
		fmt.Println("Завтра будет суббота!")
	default:
		fmt.Println("Ещё не скоро...")
	}
}

