	t := time.Now().Hour()
	switch {
	case t < 12:
		fmt.Println("Доброе утро! ☀️")
	case t < 17:
		fmt.Println("Добрый день!")
	default:
		fmt.Println("Добрый вечер! 🌙")
	}
}

